:host {
  display: block;
  width: 100%;
  height: 100%;
  font-family: 'Inter', -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
}

.nx-assign-widget {
  --nx-bg:             #ffffff;
  --nx-card-bg:        #f8fafc;
  --nx-card-border:    #e2e8f0;
  --nx-text-primary:   #0f172a;
  --nx-text-secondary: #64748b;
  --nx-text-tertiary:  #94a3b8;
  --nx-accent:         #5469ff;
  --nx-accent-light:   rgba(84,105,255,0.08);
  --nx-chip-bg:        rgba(84,105,255,0.12);
  --nx-chip-text:      #3b52e8;
  --nx-error:          #ef4444;
  --nx-radius-sm:      6px;
  --nx-radius-md:      10px;

  width: 100%;
  height: 100%;
  background: var(--nx-bg);
  box-sizing: border-box;
  overflow-y: auto;
  padding: 12px;
}

/* ── Center state ─────────────────────────────────────────────── */

.nx-center-state {
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  gap: 12px;
  height: 100%;
  min-height: 120px;
}

.nx-state-label {
  font-size: 13px;
  color: var(--nx-text-secondary);
}

.nx-icon-error {
  font-size: 28px;
  width: 28px;
  height: 28px;
  color: var(--nx-error);
}

/* ── Spinners ─────────────────────────────────────────────────── */

.nx-spinner,
.nx-spinner-sm {
  border-radius: 50%;
  border-style: solid;
  border-color: var(--nx-card-border);
  border-top-color: var(--nx-accent);
  animation: nx-spin 0.7s linear infinite;
  flex-shrink: 0;
}

.nx-spinner    { width: 28px; height: 28px; border-width: 3px; }
.nx-spinner-sm { width: 14px; height: 14px; border-width: 2px; }

@keyframes nx-spin { to { transform: rotate(360deg); } }

/* ── User list ────────────────────────────────────────────────── */

.nx-user-list {
  display: flex;
  flex-direction: column;
  gap: 6px;
}

/* ── User card ────────────────────────────────────────────────── */

.nx-user-card {
  background: var(--nx-card-bg);
  border: 1px solid var(--nx-card-border);
  border-radius: var(--nx-radius-md);
  overflow: visible;
  transition: border-color 0.15s;
}

.nx-user-card:hover {
  border-color: color-mix(in srgb, var(--nx-accent) 30%, var(--nx-card-border));
}

/* ── Card header ──────────────────────────────────────────────── */

.nx-user-header {
  display: flex;
  align-items: center;
  gap: 10px;
  padding: 10px 12px;
  cursor: pointer;
  user-select: none;
}

.nx-avatar {
  flex-shrink: 0;
  width: 32px;
  height: 32px;
  border-radius: 50%;
  background: var(--nx-accent-light);
  color: var(--nx-accent);
  font-size: 11px;
  font-weight: 700;
  display: flex;
  align-items: center;
  justify-content: center;
}

.nx-user-text {
  flex: 1 1 auto;
  min-width: 0;
  display: flex;
  flex-direction: column;
  gap: 1px;
  overflow: hidden;
}

.nx-user-name {
  font-size: 13px;
  font-weight: 600;
  color: var(--nx-text-primary);
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}

.nx-user-email {
  font-size: 11px;
  color: var(--nx-text-tertiary);
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}

.nx-user-right {
  display: flex;
  align-items: center;
  gap: 6px;
  flex-shrink: 0;
}

.nx-badge {
  font-size: 10px;
  font-weight: 600;
  background: var(--nx-accent-light);
  color: var(--nx-accent);
  border-radius: 20px;
  padding: 1px 7px;
}

.nx-chevron {
  font-size: 18px;
  width: 18px;
  height: 18px;
  color: var(--nx-text-tertiary);
  transition: transform 0.2s ease;
}

.nx-chevron-open {
  transform: rotate(90deg);
}

/* ── Card body ────────────────────────────────────────────────── */

.nx-user-body {
  padding: 0 12px 12px;
  display: flex;
  flex-direction: column;
  gap: 8px;
}

/* ── Chips ────────────────────────────────────────────────────── */

.nx-chips-row {
  display: flex;
  flex-wrap: wrap;
  gap: 5px;
  align-items: center;
  min-width: 0;
}

.nx-chip {
  display: inline-flex;
  align-items: center;
  gap: 2px;
  font-size: 11px;
  font-weight: 500;
  background: var(--nx-chip-bg);
  color: var(--nx-chip-text);
  border-radius: 20px;
  padding: 3px 4px 3px 9px;
  white-space: nowrap;
  max-width: 200px;
  overflow: hidden;
}

.nx-chip-x {
  flex-shrink: 0;
  background: none;
  border: none;
  cursor: pointer;
  color: var(--nx-chip-text);
  font-size: 15px;
  line-height: 1;
  padding: 0 3px;
  opacity: 0.55;
  border-radius: 50%;
  transition: opacity 0.15s, background 0.15s;
}

.nx-chip-x:hover {
  opacity: 1;
  background: rgba(84,105,255,0.18);
}

.nx-empty-hint {
  font-size: 11px;
  color: var(--nx-text-tertiary);
  font-style: italic;
}

/* ── Buttons ──────────────────────────────────────────────────── */

.nx-btn {
  display: inline-flex;
  align-items: center;
  gap: 4px;
  font-size: 12px;
  font-weight: 500;
  border-radius: var(--nx-radius-sm);
  padding: 5px 12px;
  cursor: pointer;
  border: 1px solid var(--nx-card-border);
  background: var(--nx-bg);
  color: var(--nx-text-primary);
  transition: background 0.15s, border-color 0.15s;
  white-space: nowrap;
}

.nx-btn:hover { background: var(--nx-card-bg); }

.nx-btn-add {
  font-size: 11px;
  color: var(--nx-accent);
  border-color: transparent;
  background: var(--nx-accent-light);
  padding: 4px 10px;
  align-self: flex-start;
}

.nx-btn-add:hover { background: rgba(84,105,255,0.15); }

.nx-btn-primary {
  background: var(--nx-accent);
  color: #fff;
  border-color: var(--nx-accent);
}

.nx-btn-primary:hover:not([disabled]) { background: #3b52e8; border-color: #3b52e8; }
.nx-btn-primary[disabled]             { opacity: 0.45; cursor: not-allowed; }

.nx-btn-ghost {
  background: transparent;
  border-color: var(--nx-card-border);
  color: var(--nx-text-secondary);
}

.nx-btn-ghost:hover { background: var(--nx-card-bg); }

/* ── Inline dropdown ──────────────────────────────────────────── */

.nx-dropdown {
  border: 1px solid var(--nx-card-border);
  border-radius: var(--nx-radius-md);
  overflow: hidden;
  background: var(--nx-bg);
}

.nx-search-row {
  display: flex;
  align-items: center;
  gap: 6px;
  padding: 8px 10px;
  border-bottom: 1px solid var(--nx-card-border);
}

.nx-icon-sm {
  font-size: 16px;
  width: 16px;
  height: 16px;
  color: var(--nx-text-tertiary);
  flex-shrink: 0;
}

.nx-search-input {
  flex: 1 1 auto;
  min-width: 0;
  border: none;
  background: transparent;
  font-size: 12px;
  color: var(--nx-text-primary);
  outline: none;
}

.nx-search-input::placeholder { color: var(--nx-text-tertiary); }

.nx-device-list {
  max-height: 180px;
  overflow-y: auto;
}

.nx-device-row {
  display: flex;
  align-items: center;
  gap: 8px;
  padding: 6px 10px;
  cursor: pointer;
  transition: background 0.1s;
  min-width: 0;
}

.nx-device-row:hover:not(.nx-row-assigned) { background: var(--nx-accent-light); }
.nx-row-will-add    { background: rgba(84,105,255,0.07); }
.nx-row-will-remove { background: rgba(239,68,68,0.06); }

.nx-check {
  flex-shrink: 0;
  accent-color: var(--nx-accent);
  cursor: inherit;
}

.nx-device-name {
  flex: 1 1 auto;
  min-width: 0;
  font-size: 12px;
  color: var(--nx-text-primary);
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}

.nx-tag-assigned {
  font-size: 9px;
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.04em;
  color: var(--nx-text-tertiary);
  flex-shrink: 0;
}

.nx-tag-remove {
  font-size: 9px;
  font-weight: 600;
  color: var(--nx-error);
  flex-shrink: 0;
}

.nx-card-actions {
  display: flex;
  gap: 6px;
  flex-wrap: wrap;
}

.nx-btn-danger {
  color: var(--nx-error);
  border-color: rgba(239,68,68,0.25);
  background: rgba(239,68,68,0.06);
}

.nx-btn-danger:hover { background: rgba(239,68,68,0.12); }

.nx-btn-link {
  flex-shrink: 0;
  background: none;
  border: none;
  cursor: pointer;
  font-size: 11px;
  font-weight: 500;
  color: var(--nx-accent);
  padding: 0 4px;
  white-space: nowrap;
}

.nx-btn-link:hover { text-decoration: underline; }

.nx-no-results {
  padding: 14px 10px;
  font-size: 12px;
  color: var(--nx-text-tertiary);
  text-align: center;
}

/* ── Dropdown footer ──────────────────────────────────────────── */

.nx-dropdown-footer {
  display: flex;
  align-items: center;
  flex-wrap: wrap;
  gap: 6px;
  padding: 8px 10px;
  border-top: 1px solid var(--nx-card-border);
}

.nx-sel-count {
  flex: 1 1 auto;
  min-width: 0;
  font-size: 11px;
  font-weight: 500;
  color: var(--nx-accent);
}

.nx-footer-btns {
  display: flex;
  gap: 6px;
  flex-shrink: 0;
}

.nx-footer-error {
  flex: 0 0 100%;
}

/* ── Error states ─────────────────────────────────────────────── */

.nx-inline-error {
  font-size: 11px;
  color: var(--nx-error);
}

.nx-user-error-body {
  padding: 8px 12px 12px;
  display: flex;
  align-items: center;
  gap: 8px;
  flex-wrap: wrap;
}

.nx-error-text {
  flex: 1 1 auto;
  min-width: 0;
  font-size: 12px;
  color: var(--nx-error);
}

/* ── Dark mode ────────────────────────────────────────────────── */

@media (prefers-color-scheme: dark) {
  .nx-assign-widget {
    --nx-bg:             #0f172a;
    --nx-card-bg:        #1e293b;
    --nx-card-border:    #334155;
    --nx-text-primary:   #f1f5f9;
    --nx-text-secondary: #94a3b8;
    --nx-text-tertiary:  #64748b;
    --nx-chip-bg:        rgba(84,105,255,0.22);
    --nx-chip-text:      #818cf8;
    --nx-accent-light:   rgba(84,105,255,0.15);
  }
}

descriptor.controllerScript:
self.onInit = function() {
  var ctx = self.ctx;
  var s   = ctx.$scope;

  self._deviceMap = {};

  s.loading = true;
  s.error   = null;
  s.users   = [];
  s.devices = [];
  s.dropdown = { userId: null, search: '', selection: {}, applying: false, error: null };

  // ── Template helpers ──────────────────────────────────────────

  s.getDeviceName = function(deviceId) {
    return self._deviceMap[deviceId] ? self._deviceMap[deviceId].name : deviceId;
  };

  s.filteredDevices = function() {
    var q = (s.dropdown.search || '').toLowerCase();
    if (!q) return s.devices;
    return s.devices.filter(function(d) {
      return d.name.toLowerCase().indexOf(q) !== -1;
    });
  };

  s.isAssigned = function(deviceId) {
    var user = activeUser();
    return user ? !!user.assignedMap[deviceId] : false;
  };

  s.pendingCount = function() {
    return Object.keys(s.dropdown.pending).length;
  };

  // ── Card interactions ─────────────────────────────────────────

  s.toggleUser = function(user) {
    if (user.state === 'collapsed') {
      loadUserRelations(user);
    } else {
      if (s.dropdown.userId === user.id) {
        s.dropdown.userId = null;
      }
      user.state = 'collapsed';
      ctx.detectChanges();
    }
  };

  s.loadUserRelations = function(user) {
    loadUserRelations(user);
  };

  // ── Dropdown ──────────────────────────────────────────────────

  s.openDropdown = function(user) {
    // Seed selection with current assignments so assigned devices start checked
    var sel = {};
    user.assignedList.forEach(function(did) { sel[did] = true; });
    s.dropdown.userId     = user.id;
    s.dropdown.search     = '';
    s.dropdown.selection  = sel;
    s.dropdown.error      = null;
    s.dropdown.applying   = false;
    ctx.detectChanges();
  };

  s.closeDropdown = function() {
    s.dropdown.userId    = null;
    s.dropdown.selection = {};
    s.dropdown.error     = null;
    ctx.detectChanges();
  };

  s.onDropdownSearch = function(event) {
    s.dropdown.search = event.target.value;
    ctx.detectChanges();
  };

  s.toggleSelection = function(deviceId) {
    var sel = s.dropdown.selection;
    if (sel[deviceId]) { delete sel[deviceId]; } else { sel[deviceId] = true; }
    ctx.detectChanges();
  };

  s.selectAllVisible = function() {
    var filtered = s.filteredDevices();
    filtered.forEach(function(d) { s.dropdown.selection[d.id] = true; });
    ctx.detectChanges();
  };

  s.changesCount = function() {
    var user = activeUser();
    if (!user) return 0;
    var sel   = s.dropdown.selection;
    var count = 0;
    s.devices.forEach(function(d) {
      if (!!sel[d.id] !== !!user.assignedMap[d.id]) count++;
    });
    return count;
  };

  s.applyChanges = function() {
    var user = activeUser();
    if (!user) return;

    var sel      = s.dropdown.selection;
    var toAdd    = [];
    var toRemove = [];

    s.devices.forEach(function(d) {
      var inSel = !!sel[d.id];
      var inMap = !!user.assignedMap[d.id];
      if (inSel && !inMap)  toAdd.push(d.id);
      if (!inSel && inMap)  toRemove.push(d.id);
    });

    if (!toAdd.length && !toRemove.length) { s.closeDropdown(); return; }

    s.dropdown.applying = true;
    s.dropdown.error    = null;
    ctx.detectChanges();

    var remaining = toAdd.length + toRemove.length;
    var anyFailed = false;

    function finalize() {
      if (--remaining > 0) return;
      s.dropdown.applying = false;
      if (anyFailed) {
        s.dropdown.error = 'Algunos cambios fallaron. Reintentá.';
      } else {
        s.dropdown.userId    = null;
        s.dropdown.selection = {};
        s.dropdown.error     = null;
      }
      ctx.detectChanges();
    }

    toAdd.forEach(function(deviceId) {
      proxyWrite('create', user.id, deviceId).then(function() {
        if (!user.assignedMap[deviceId]) {
          user.assignedMap[deviceId] = true;
          user.assignedList.push(deviceId);
        }
        finalize();
      }).catch(function() { anyFailed = true; finalize(); });
    });

    toRemove.forEach(function(deviceId) {
      proxyWrite('delete', user.id, deviceId).then(function() {
          delete user.assignedMap[deviceId];
          user.assignedList = user.assignedList.filter(function(id) { return id !== deviceId; });
          finalize();
        }).catch(function() { anyFailed = true; finalize(); });
    });
  };

  s.clearAllDevices = function(user) {
    if (!user.assignedList.length) return;
    var deviceIds = user.assignedList.slice();
    var remaining = deviceIds.length;
    var anyFailed = false;

    user.assignedMap  = {};
    user.assignedList = [];
    user.error        = null;
    ctx.detectChanges();

    deviceIds.forEach(function(deviceId) {
      proxyWrite('delete', user.id, deviceId).then(function() {
          if (--remaining === 0 && anyFailed) loadUserRelations(user);
        })
        .catch(function() {
          anyFailed = true;
          if (--remaining === 0) {
            user.error = 'Algunos no pudieron eliminarse.';
            loadUserRelations(user);
          }
        });
    });
  };

  s.removeDevice = function(user, deviceId) {
    delete user.assignedMap[deviceId];
    user.assignedList = user.assignedList.filter(function(id) { return id !== deviceId; });
    user.error = null;
    ctx.detectChanges();

    proxyWrite('delete', user.id, deviceId).catch(function() {
        user.assignedMap[deviceId] = true;
        user.assignedList.push(deviceId);
        user.error = 'Error al desasignar. Intentá de nuevo.';
        ctx.detectChanges();
      });
  };

  s.initLoad = function() { initLoad(); };

  var proxyUrl = (ctx.settings && ctx.settings.proxyUrl) || '';
  if (!proxyUrl) {
    s.loading = false;
    s.error   = 'Proxy URL no configurado. Revisá los settings del widget.';
    ctx.detectChanges();
    return;
  }

  initLoad();
};

self.onDataUpdated = function() {};
self.onResize      = function() {};
self.onDestroy     = function() {};

// ── Private ───────────────────────────────────────────────────────

function initLoad() {
  var ctx = self.ctx;
  var s   = ctx.$scope;
  var cid = customerId();

  s.loading = true;
  s.error   = null;
  ctx.detectChanges();

  if (!cid) {
    s.loading = false;
    s.error   = 'No se pudo obtener el ID de customer. Abrí la consola para más info.';
    ctx.detectChanges();
    return;
  }

  var pending = 2;
  var usersData, devicesData;
  var failed = false;

  function checkDone() {
    if (--pending > 0) return;
    if (failed) {
      s.loading = false;
      s.error   = 'Error al cargar usuarios o devices. Revisá la conexión.';
      ctx.detectChanges();
      return;
    }

    self._deviceMap = {};
    var devList = (devicesData && devicesData.data) ? devicesData.data : (devicesData || []);
    s.devices = devList.map(function(d) {
      var dev = { id: d.id.id, name: d.label || d.name };
      self._deviceMap[dev.id] = dev;
      return dev;
    });

    var userList = (usersData && usersData.data) ? usersData.data : (usersData || []);
    s.users = userList.map(function(u) {
      var first    = u.firstName || '';
      var last     = u.lastName  || '';
      var fullName = (first + ' ' + last).trim() || u.email || '—';
      var initials = ((first[0] || '') + (last[0] || '')).toUpperCase()
                   || (u.email ? u.email[0].toUpperCase() : '?');
      return {
        id:           u.id.id,
        name:         fullName,
        email:        u.email || '',
        initials:     initials,
        state:        'collapsed',
        assignedMap:  {},
        assignedList: [],
        error:        null
      };
    });

    s.loading = false;
    ctx.detectChanges();
  }

  ctx.http.get('/api/users?pageSize=50&page=0').subscribe(
    function(data) { usersData   = data; checkDone(); },
    function()     { failed = true;       checkDone(); }
  );

  ctx.http.get('/api/customer/' + cid + '/devices?pageSize=100&page=0').subscribe(
    function(data) { devicesData = data; checkDone(); },
    function()     { failed = true;       checkDone(); }
  );
}

function loadUserRelations(user) {
  var ctx = self.ctx;

  user.state = 'loading';
  user.error = null;
  ctx.detectChanges();

  var url = '/api/relations?fromId=' + user.id +
            '&fromType=USER&relationType=Manages&toEntityType=DEVICE';

  ctx.http.get(url).subscribe(
    function(data) {
      var rels = data || [];
      user.assignedMap  = {};
      user.assignedList = [];
      rels.forEach(function(rel) {
        var did = rel.to && rel.to.id;
        if (did && !user.assignedMap[did]) {
          user.assignedMap[did] = true;
          user.assignedList.push(did);
        }
      });
      user.state = 'ready';
      ctx.detectChanges();
    },
    function() {
      user.state = 'error';
      user.error = 'Error al cargar relaciones.';
      ctx.detectChanges();
    }
  );
}

function activeUser() {
  var s      = self.ctx.$scope;
  var userId = s.dropdown.userId;
  if (!userId) return null;
  for (var i = 0; i < s.users.length; i++) {
    if (s.users[i].id === userId) return s.users[i];
  }
  return null;
}

// Writes route through n8n proxy — proxy holds tenant admin credentials,
// no token is exposed in widget settings.
function proxyWrite(action, userId, deviceId) {
  var settings = self.ctx.settings || {};
  var proxyUrl = settings.proxyUrl     || '';
  var secret   = settings.widgetSecret || '';
  return fetch(proxyUrl, {
    method:  'POST',
    headers: { 'Content-Type': 'application/json', 'X-Widget-Secret': secret },
    body: JSON.stringify({
      action:       action,
      fromId:       userId,
      fromType:     'USER',
      toId:         deviceId,
      toType:       'DEVICE',
      relationType: 'Manages'
    })
  }).then(function(res) {
    if (!res.ok) return res.text().then(function(msg) {
      throw new Error(msg || ('HTTP ' + res.status));
    });
  });
}

function customerId() {
  // TB PE may expose currentCustomerId as entity-ID object {id, entityType} or plain string
  var cid = self.ctx.currentCustomerId;
  if (cid) {
    if (typeof cid === 'object' && typeof cid.id === 'string') return cid.id;
    if (typeof cid === 'string' && cid.length > 0)            return cid;
  }
  // Fallback: JWT payload — customer users always have customerId as a UUID string
  var jwtCid = self.ctx.currentUser && self.ctx.currentUser.customerId;
  if (jwtCid && typeof jwtCid === 'string' && jwtCid.length === 36) return jwtCid;

  console.warn('[device-assignment] ctx.currentCustomerId:', self.ctx.currentCustomerId,
               '| ctx.currentUser.customerId:', self.ctx.currentUser && self.ctx.currentUser.customerId);
  return null;
}

